  var _drawer=document.createElement('div');
  _drawer.style.cssText='position:fixed;top:0;right:0;height:100%;width:400px;max-width:92vw;background:var(--notion-card,#fff);color:inherit;box-shadow:-6px 0 24px rgba(0,0,0,.18);transform:translateX(100%);transition:transform .22s ease;z-index:9999;display:flex;flex-direction:column;';
  _drawer.innerHTML='<div style="padding:14px 16px;border-bottom:1px solid var(--notion-border,#eee);display:flex;align-items:center;gap:8px;"><b id="stkDwTitle" style="flex:1;font-size:15px;"></b><button id="stkDwClose" style="border:0;background:var(--notion-bg,#f2f2f2);color:inherit;border-radius:6px;padding:5px 12px;cursor:pointer;">й—ңй–ү</button></div><div id="stkDwBody" style="padding:14px 16px;overflow:auto;flex:1;font-size:13px;line-height:1.7;"></div>';
  document.body.appendChild(_drawer);
