    document.getElementById('stkDwTitle').textContent=(code||'')+'гҖҖ'+(name||'');
    var body=document.getElementById('stkDwBody');
    body.innerHTML='<div style="color:var(--notion-text-light,#888);">жҹҘи©ўиҝ‘жңҹйҖІйҠ·зҙҖйҢ„дёӯвҖҰпјҲз¶“е…§з¶Іе°Ҹе№«жүӢпјҢзҙ„ж•ёз§’пјү</div>';
    fetch('/admin/inventory/stock/txn-request',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({code:code})}).catch(function(){});
    var tries=0;
