    router.post("/inventory/stocktake-groups", express_1.default.urlencoded({ extended: true }), async (req, res) => {
        try {
            const grpMap = (req.body && typeof req.body.grp === "object" && req.body.grp) ? req.body.grp : {};
            const manualRaw = String((req.body && req.body.manual_ids) || "");
            const chosen = new Map(); // group_id -> name
            const cands = await loadStocktakeGroupCandidates();
            const nameById = new Map(cands.map((c) => [c.group_id, c.name || ""]));
            for (const k of Object.keys(grpMap)) { const id = String(k).trim(); if (id) chosen.set(id, nameById.get(id) || ""); }
            for (const line of manualRaw.split(/[\r\n,]+/)) { const id = line.trim(); if (id) chosen.set(id, chosen.get(id) || nameById.get(id) || ""); }
            const now = new Date().toISOString();
            await db.prepare("DELETE FROM stocktake_group").run();
            for (const [gid, name] of chosen) {
                await db.prepare("INSERT INTO stocktake_group (group_id, group_name, created_at) VALUES (?, ?, ?)").run(gid, name || null, now);
            }
            res.redirect("/admin/inventory/stocktake-groups?ok=1");
        }
        catch (e) {
            console.error("[admin] stocktake-groups save", e?.message || e);
            res.status(500).send("е„ІеӯҳеӨұж•—пјҡ" + String(e?.message || e));
        }
    });
    router.get("/inventory/variance-report", async (req, res) => {
        const warehouses = await db.prepare("SELECT id, name FROM inventory_warehouses ORDER BY sort_order, name").all();
        const dateFrom = (req.query.date_from || "").trim();
        const dateTo = (req.query.date_to || "").trim();
        const whId = (req.query.warehouse_id || "").trim();
        const exportCsv = req.query.export === "csv";
        let rows = [];
        let freqList = [];
        if (dateFrom && dateTo && /^\d{4}-\d{2}-\d{2}$/.test(dateFrom) && /^\d{4}-\d{2}-\d{2}$/.test(dateTo)) {
            const from = new Date(dateFrom);
            const to = new Date(dateTo);
            if (from <= to) {
                const warehouseIds = whId ? [whId] : warehouses.map((w) => w.id);
                const productNames = {};
                const whNames = {};
                warehouses.forEach((w) => { whNames[w.id] = w.name; });
                const prods = await db.prepare("SELECT id, name FROM products").all();
                prods.forEach((p) => { productNames[p.id] = p.name; });
                const varianceCount = {};
                for (let d = new Date(from); d <= to; d.setDate(d.getDate() + 1)) {
                    const dateStr = d.toISOString().slice(0, 10);
                    for (const wid of warehouseIds) {
                        const prevRec = await db.prepare("SELECT items FROM daily_inventory WHERE warehouse_id = ? AND record_date < ? ORDER BY record_date DESC LIMIT 1").get(wid, dateStr);
                        const currRec = await db.prepare("SELECT items FROM daily_inventory WHERE warehouse_id = ? AND record_date = ?").get(wid, dateStr);
                        const erpRows = await db.prepare("SELECT product_id, SUM(qty_sold) as total FROM erp_sales WHERE warehouse_id = ? AND record_date = ? GROUP BY product_id").all(wid, dateStr);
                        const erpByProduct = Object.fromEntries((erpRows || []).map((r) => [r.product_id, Number(r.total) || 0]));
                        const prevItems = prevRec && prevRec.items ? (typeof prevRec.items === "string" ? JSON.parse(prevRec.items || "{}") : prevRec.items) : {};
                        const currItems = currRec && currRec.items ? (typeof currRec.items === "string" ? JSON.parse(currRec.items || "{}") : currRec.items) : {};
                        const allProductIds = new Set([...Object.keys(prevItems), ...Object.keys(currItems), ...Object.keys(erpByProduct)]);
                        for (const pid of allProductIds) {
                            const prevQty = Number(prevItems[pid]) || 0;
                            const currQty = currItems[pid] != null ? Number(currItems[pid]) : null;
                            const erpQty = erpByProduct[pid] || 0;
                            const book = prevQty - erpQty;
                            if (currQty === null)
                                continue;
                            const variance = currQty - book;
                            if (Math.abs(variance) > 1e-6) {
                                rows.push({ date: dateStr, warehouse_id: wid, warehouse_name: whNames[wid] || wid, product_id: pid, product_name: productNames[pid] || pid, book, curr: currQty, variance });
                                varianceCount[pid] = (varianceCount[pid] || 0) + 1;
                            }
                        }
                    }
                }
                freqList = Object.entries(varianceCount).sort((a, b) => b[1] - a[1]).map(([pid, count]) => ({ product_id: pid, product_name: productNames[pid] || pid, count }));
            }
        }
        if (exportCsv && rows.length) {
            const BOM = "\uFEFF";
            const csv = BOM + "ж—Ҙжңҹ,еҖүеә«,е“Ғй …,еёійқўж•ёйҮҸ,зӣӨй»һж•ёйҮҸ,зӣӨе·®\n" + rows.map((r) => [r.date, r.warehouse_name, r.product_name, r.book, r.curr, r.variance].join(",")).join("\n");
            res.type("text/csv").set("Content-Disposition", "attachment; filename=variance-report.csv").send(csv);
            return;
        }
        const optWh = warehouses.map((w) => `<option value="${escapeAttr(w.id)}" ${w.id === whId ? "selected" : ""}>${escapeHtml(w.name)}</option>`).join("");
        const body = `
        <div class="notion-breadcrumb"><a href="/admin">е„ҖиЎЁжқҝ</a> / <a href="/admin/inventory/legacy">зӣӨй»һдҪңжҘӯ</a> / зӣӨе·®е ұиЎЁ</div>
        <h1 class="notion-page-title">зӣӨе·®е ұиЎЁ</h1>
        <p>дҫқж—ҘжңҹеҚҖй–“иҲҮеҖүеә«иЁҲз®—зӣӨе·®пјҲзӣӨй»һж•ёйҮҸ вҲ’ еёійқўж•ёйҮҸпјҢеёійқў = еүҚж—ҘзӣӨй»һ вҲ’ з•¶ж—Ҙ ERP йҠ·иІЁпјүгҖӮеҸҜеҢҜеҮә CSVпјҢдёҰжӘўиҰ–жҳ“зӣӨе·®е“Ғй …зөұиЁҲгҖӮ</p>
        <div class="notion-card">
          <form method="get" action="/admin/inventory/variance-report" style="margin-bottom:16px;display:flex;flex-wrap:wrap;gap:12px;align-items:center;">
            <label>ж—Ҙжңҹиө· <input type="date" name="date_from" value="${escapeAttr(dateFrom)}"></label>
            <label>ж—ҘжңҹиЁ– <input type="date" name="date_to" value="${escapeAttr(dateTo)}"></label>
            <label>еҖүеә« <select name="warehouse_id"><option value="">е…ЁйғЁ</option>${optWh}</select></label>
            <button type="submit" class="btn">жҹҘи©ў</button>
          </form>
          ${rows.length ? `<p><a href="/admin/inventory/variance-report?date_from=${encodeURIComponent(dateFrom)}&date_to=${encodeURIComponent(dateTo)}&warehouse_id=${encodeURIComponent(whId)}&export=csv" class="btn btn-primary">еҢҜеҮә CSVпјҲ${rows.length} зӯҶпјү</a></p>` : ""}
          <h3>жҳ“зӣӨе·®е“Ғй …пјҲеҚҖй–“е…§еҮәзҸҫзӣӨе·®ж¬Ўж•ёпјү</h3>
          ${freqList.length ? `<table><thead><tr><th>е“Ғй …</th><th>зӣӨе·®ж¬Ўж•ё</th></tr></thead><tbody>${freqList.map((f) => `<tr><td>${escapeHtml(f.product_name)}</td><td>${f.count}</td></tr>`).join("")}</tbody></table>` : "<p>и«ӢйҒёж“Үж—ҘжңҹеҚҖй–“дёҰжҹҘи©ўгҖӮ</p>"}
          <h3>зӣӨе·®жҳҺзҙ°</h3>
          ${rows.length ? `<table><thead><tr><th>ж—Ҙжңҹ</th><th>еҖүеә«</th><th>е“Ғй …</th><th>еёійқў</th><th>зӣӨй»һ</th><th>зӣӨе·®</th></tr></thead><tbody>${rows.slice(0, 500).map((r) => `<tr><td>${r.date}</td><td>${escapeHtml(r.warehouse_name)}</td><td>${escapeHtml(r.product_name)}</td><td>${r.book}</td><td>${r.curr}</td><td style="color:${r.variance !== 0 ? "#c00" : ""}">${r.variance}</td></tr>`).join("")}</tbody></table>${rows.length > 500 ? "<p>еғ…йЎҜзӨәеүҚ 500 зӯҶпјҢи«Ӣз”ЁеҢҜеҮә CSV еҸ–еҫ—е®Ңж•ҙиіҮж–ҷгҖӮ</p>" : ""}` : "<p>и«ӢйҒёж“Үж—ҘжңҹеҚҖй–“дёҰжҹҘи©ўгҖӮ</p>"}
        </div>
      `;
        res.type("text/html").send(notionPage("зӣӨе·®е ұиЎЁ", body, "inv-report", res));
    });
