    router.get("/freezer-fridge", async (req, res) => {
        const warehouses = await db.prepare("SELECT id, name, sort_order, compliant_temp, power_compliant, light_compliant, heat_compliant FROM freezer_fridge_warehouses ORDER BY sort_order, name").all();
        const month = req.query.month?.trim() || new Date().toISOString().slice(0, 7);
        const [y, m] = month.split("-").map(Number);
        const nextMonthFirst = m === 12 ? (y + 1) + "-01-01" : y + "-" + String(m + 1).padStart(2, "0") + "-01";
        const records = await db.prepare("SELECT date, filler_name, confirmed_at, anomaly FROM freezer_fridge_daily WHERE date >= ? AND date < ? ORDER BY date").all(month + "-01", nextMonthFirst);
        const recordByDate = {};
        records.forEach((r) => { recordByDate[r.date] = r; });
        const firstDay = new Date(y, m - 1, 1);
        const daysInMonth = new Date(y, m, 0).getDate();
        const calRows = [];
        let week = [];
        const startPad = firstDay.getDay();
        for (let i = 0; i < startPad; i++)
            week.push("");
        for (let d = 1; d <= daysInMonth; d++) {
            const dateStr = month + "-" + String(d).padStart(2, "0");
            const rec = recordByDate[dateStr];
            week.push(rec ? `<a href="/admin/freezer-fridge/daily?date=${dateStr}" class="cal-day filled">${d}</a>` : `<a href="/admin/freezer-fridge/daily?date=${dateStr}" class="cal-day">${d}</a>`);
            if (week.length === 7) {
                calRows.push(week);
                week = [];
            }
        }
        if (week.length)
            calRows.push(week);
        const calHtml = "<table class=\"freezer-cal\"><thead><tr><th>ж—Ҙ</th><th>дёҖ</th><th>дәҢ</th><th>дёү</th><th>еӣӣ</th><th>дә”</th><th>е…ӯ</th></tr></thead><tbody>" + calRows.map((row) => "<tr>" + row.map((cell) => "<td>" + (cell || "") + "</td>").join("") + "</tr>").join("") + "</tbody></table>";
        const body = `
        <div class="notion-breadcrumb"><a href="/admin">е„ҖиЎЁжқҝ</a> / з’°еўғиЎӣз”ҹз®ЎзҗҶ / еҶ·еҮҚеә«еҶ·и—Ҹеә«жӘўжҹҘиЎЁ</div>
        <h1 class="notion-page-title">еҶ·еҮҚеә«еҶ·и—Ҹеә«жӘўжҹҘиЎЁ</h1>
        <p class="notion-hint" style="margin-bottom:16px;">жҜҸж—ҘеЎ«еҜ«еҗ„еә«жҲҝжә«еәҰгҖҒйӣ»жәҗгҖҒйӣ»зҮҲгҖҒйӣ»зҶұпјӣи«Ӣе…ҲиҮігҖҢеә«жҲҝз®ЎзҗҶгҖҚж–°еўһеә«жҲҝгҖӮ</p>
        <p style="margin-bottom:16px;"><a href="/admin/freezer-fridge/warehouses" class="btn">еә«жҲҝз®ЎзҗҶ</a>пјҲе…ұ ${warehouses.length} еҖӢеә«жҲҝпјү</p>
        <div class="notion-card">
          <h2>${month} жңҲжӣҶ</h2>
          <form method="get" action="/admin/freezer-fridge" style="margin-bottom:12px;">
            <input type="month" name="month" value="${escapeAttr(month)}"> <button type="submit" class="btn">еҲҮжҸӣжңҲд»Ҫ</button>
          </form>
          ${calHtml}
          <p class="notion-hint" style="margin-top:12px;">й»һйҒёж—ҘжңҹеЎ«еҜ«з•¶ж—ҘжӘўжҹҘиЎЁгҖӮ</p>
        </div>
        <div class="notion-card">
          <h2>з•¶жңҲеЎ«иЎЁзҙҖйҢ„</h2>
          ${records.length ? "<table><thead><tr><th>ж—Ҙжңҹ</th><th>еЎ«иЎЁдәә</th><th>зӢҖж…Ӣ</th><th>ж“ҚдҪң</th></tr></thead><tbody>" + records.map((r) => `<tr><td>${r.date}</td><td>${escapeHtml(r.filler_name || "")}</td><td>${r.confirmed_at ? "е·ІзўәиӘҚ" : "е·ІеЎ«"}${r.anomaly ? "гҖҒз•°еёё" : ""}</td><td><a href="/admin/freezer-fridge/daily?date=${r.date}">з·ЁијҜ</a></td></tr>`).join("") + "</tbody></table>" : "<p>жң¬жңҲе°ҡз„ЎеЎ«иЎЁзҙҖйҢ„</p>"}
        </div>
      `;
        res.type("text/html").send(notionPage("еҶ·еҮҚеә«еҶ·и—Ҹеә«жӘўжҹҘиЎЁ", body + "\n<style>.freezer-cal td,.freezer-cal th{border:1px solid var(--notion-border);padding:8px;min-width:40px;}.freezer-cal .cal-day{display:block;text-align:center;text-decoration:none;color:var(--notion-accent);}.freezer-cal .cal-day.filled{font-weight:600;}</style>", "env", res));
    });
