        <div class="notion-card">
          <h2>жҢҮе®ҡж—ҘжңҹиЁӮе–®${customerId ? "пјҲе·ІзҜ©йҒёе®ўжҲ¶пјү" : ""}</h2>
          <table>
            <thead><tr><th>ж—Ҙжңҹ</th><th>е®ўжҲ¶</th><th></th></tr></thead>
            <tbody>${rows.length ? rows : "<tr><td colspan='3'>з„ЎиЁӮе–®</td></tr>"}</tbody>
          </table>
          ${orders.length ? `<p style="margin-top:12px;"><a href="/admin/export/download?date=${encodeURIComponent(date)}${customerId ? "&customer_id=" + encodeURIComponent(customerId) : ""}" class="btn">еҢҜеҮә CSV</a></p>` : ""}
        </div>
