        const batchMoveBarHtml = `
            <div class="order-batch-move-bar" style="margin:0 0 12px;padding:10px 12px;background:var(--notion-sidebar);border-radius:6px;border:1px solid var(--notion-border);display:flex;flex-wrap:wrap;gap:10px;align-items:center;">
              <span style="font-weight:600;font-size:13px;">жүӢеӢ•жӢҶдҪөе–®</span>
              <label style="margin:0;display:flex;align-items:center;gap:6px;font-size:13px;">
                <span>зӣ®жЁҷеӯҗе®ўжҲ¶</span>
                <select id="target_sub_customer" style="min-width:11rem;padding:4px 8px;">${subCustomerSelectOpts}</select>
              </label>
              <input type="text" id="target_sub_customer_custom" placeholder="йҒёгҖҢиҮӘиЁӮгҖҚжҲ–йЎҚеӨ–ијёе…ҘжӯЈејҸеҗҚзЁұ" style="min-width:12rem;max-width:20rem;padding:4px 8px;" />
              <button type="button" id="btn_move_items" class="btn btn-primary">иҪүз§»йҒёеҸ–е“Ғй …</button>
              <button type="button" id="btn_split_by_subcust" class="btn" title="жҠҠжңүеЎ«гҖҢеӯҗе®ўжҲ¶гҖҚзҡ„е“Ғй …еҗ„иҮӘжӢҶжҲҗзҚЁз«ӢиЁӮе–®пјҲжҜҸеҖӢеӯҗе®ўжҲ¶дёҖзӯҶпјүпјҢдёҰиҮӘеӢ•иЈңи©Іи·Ҝз·ҡз©әзұғпјӣеҜ©ж ёжҷӮе°ұжҳҜеҲҶй–Ӣзҡ„е…©зӯҶе–®">дҫқеӯҗе®ўжҲ¶жӢҶе–®</button>
              <span id="move_items_status" style="font-size:12px;color:var(--notion-text-secondary);"></span>
            </div>`;
        const orderStatusLc = String(order.status || "").toLowerCase();
        const orderStatusDisplay = orderStatusLc === "approved" ? "е·ІзўәиӘҚ" : orderStatusLc === "pending" ? "еҫ…зўәиӘҚ" : orderStatusLc === "deleted" ? "е·ІдҪңе»ў" : orderStatusLc === "complaint" ? "е®ўиЁҙ" : escapeHtml(String(order.status || ""));
        const confirmOrderFormHtml = orderStatusLc === "approved"
