            await db.prepare(`INSERT INTO prompt_versions (id, slot, label, body, notes, created_at, updated_at) VALUES (?, ?, ?, ?, ?, ${nowSql}, ${nowSql})`).run(newId, slot, newLabel, src.body, "з”ұиӨҮиЈҪе»әз«Ӣ");
