    router.post("/import", upload, async (req, res) => {
        try {
            const sheet = parseRequestToSheet(req);
            if (!sheet || sheet.rows.length === 0) {
                res.redirect("/admin/import?err=" + encodeURIComponent("и«ӢиІјдёҠ CSV жҲ–дёҠеӮі Excel жӘ”жЎҲ"));
                return;
            }
            const defaultUnit = (req.body?.default_unit?.trim()) || "е…¬ж–Ө";
            const { header, rows } = sheet;
            const h = (i) => (header[i] ?? "").trim().toLowerCase().replace(/\s+/g, "_");
            const nameIdx = header.findIndex((_, i) => {
                const v = h(i);
                return ["жЁҷжә–е“ҒеҗҚ", "е“ҒеҗҚ", "еҗҚзЁұ", "name", "commname", "comm_name"].includes(v);
            });
            const erpIdx = header.findIndex((_, i) => ["erpж–ҷиҷҹ", "erp_code", "hqplucode"].includes(h(i)));
            const teraokaIdx = header.findIndex((_, i) => ["еҜәеІЎжўқзўј", "teraoka_barcode", "plucode"].includes(h(i)));
            const unitIdx = header.findIndex((_, i) => ["е–®дҪҚ", "unit", "qtysymbol"].includes(h(i)));
            if (nameIdx === -1) {
                const headerPreview = header.length > 12 ? header.slice(0, 12).join("гҖҒ") + "вҖҰ" : header.join("гҖҒ") || "пјҲз„Ўпјү";
                res.redirect("/admin/import?err=" + encodeURIComponent("жүҫдёҚеҲ°е“ҒеҗҚж¬„дҪҚпјҲи«Ӣжңү CommNameгҖҒжЁҷжә–е“ҒеҗҚгҖҒе“ҒеҗҚжҲ– nameпјүгҖӮеҒөжё¬еҲ°зҡ„жЁҷйЎҢпјҡ" + headerPreview));
                return;
            }
            let imported = 0;
            const existingNames = new Set((await db.prepare("SELECT name FROM products").all()).map((r) => r.name));
            for (let i = 0; i < rows.length; i++) {
                const cols = rows[i];
                const name = (cols[nameIdx] ?? "").trim();
                if (!name)
                    continue;
                if (existingNames.has(name))
                    continue;
                const erpCode = erpIdx >= 0 ? (cols[erpIdx] ?? "").trim() || null : null;
                const teraoka = teraokaIdx >= 0 ? (cols[teraokaIdx] ?? "").trim() || null : null;
                const unitCell = unitIdx >= 0 ? (cols[unitIdx] ?? "").trim() : "";
                const unit = unitCell || defaultUnit;
                const id = (0, id_js_1.newId)("prod");
                await db.prepare("INSERT INTO products (id, name, erp_code, teraoka_barcode, unit) VALUES (?, ?, ?, ?, ?)").run(id, name, erpCode, teraoka, unit);
                existingNames.add(name);
                imported++;
            }
            res.redirect("/admin/import?ok=" + imported);
        }
        catch (e) {
            console.error("[admin] еҢҜе…Ҙе“Ғй …йҢҜиӘӨ:", e);
            const msg = (e && e.message) ? String(e.message) : String(e);
            res.redirect("/admin/import?err=" + encodeURIComponent("еҢҜе…ҘеӨұж•—пјҡ" + (msg.length > 200 ? msg.slice(0, 200) + "вҖҰ" : msg)));
        }
    });
